import{_ as e}from"./chunks/subs-usage-warning.Bdji-M7h.js";import{_ as a,o as n,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Subscriptions & Usage — Overview","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/overview.md","filePath":"subscriptions/overview.md"}'),s={name:"subscriptions/overview.md"};function l(o,t,g,h,c,d){return n(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="subscriptions-usage-—-overview" tabindex="-1">Subscriptions &amp; Usage — Overview <a class="header-anchor" href="#subscriptions-usage-—-overview" aria-label="Permalink to &quot;Subscriptions &amp; Usage — Overview&quot;">​</a></h1><p>Every kingdom and alliance in the tracker runs on a <strong><a href="./../getting-started/glossary.html#plan">plan</a></strong>. Your plan decides two things:</p><ol><li><strong>How much you can store</strong> — limits (called <a href="./../getting-started/glossary.html#quota--limit">quotas</a>) on players, events, screenshots, storage, and so on.</li><li><strong>Which extra features you get</strong> — <a href="./../getting-started/glossary.html#premium-feature">premium features</a> like advanced analytics and recommendations.</li></ol><p>You don&#39;t need to buy anything to use the tracker. Everyone starts on a <strong>free tier</strong> that covers normal use. Premium plans simply raise the limits and switch on extra features. This page explains the moving parts; the rest of this section covers each in detail.</p><h2 id="the-pieces-in-plain-terms" tabindex="-1">The pieces, in plain terms <a class="header-anchor" href="#the-pieces-in-plain-terms" aria-label="Permalink to &quot;The pieces, in plain terms&quot;">​</a></h2><ul><li><strong><a href="./../getting-started/glossary.html#plan">Plan</a></strong> — your tier. There are free tiers and premium tiers, for kingdoms and for alliances.</li><li><strong><a href="./../getting-started/glossary.html#effective-plan">Effective plan</a></strong> — the plan that <em>actually applies to you right now</em>. Because a plan can come from a few different places, the app works out which one wins. See <a href="./effective-plan.html">Which Plan Applies to You</a>.</li><li><strong><a href="./../getting-started/glossary.html#quota--limit">Quota / limit</a></strong> — the ceiling on each kind of thing (players, screenshots, etc.). As you approach a ceiling you get warnings. See <a href="./quota-warnings.html">Quota Warnings</a>.</li><li><strong><a href="./../getting-started/glossary.html#premium-feature">Premium feature</a></strong> — an extra capability a premium plan unlocks. See <a href="./premium-features.html">Premium Features</a>.</li><li><strong><a href="./../getting-started/glossary.html#grant">Grant</a></strong> — a King sharing the kingdom&#39;s premium plan with an alliance. See <a href="./kingdom-grants.html">Kingdom Grants</a>.</li><li><strong><a href="./../getting-started/glossary.html#suspension">Suspension</a></strong> — a paused, mostly read-only state, usually from hitting limits. See <a href="./suspension.html">Suspension &amp; Limited Mode</a>.</li></ul><h2 id="the-subscription-usage-panel" tabindex="-1">The Subscription &amp; Usage panel <a class="header-anchor" href="#the-subscription-usage-panel" aria-label="Permalink to &quot;The Subscription &amp; Usage panel&quot;">​</a></h2><p>Wherever you manage a kingdom or alliance, there&#39;s a <strong>Subscription &amp; Usage</strong> panel that answers &quot;how am I doing?&quot; at a glance:</p><ul><li>Your current <strong>plan</strong> and where it came from (the <strong>plan source</strong> label).</li><li>A <strong>status</strong> pill (OK, warning, critical, exceeded, or suspended).</li><li>A <strong>bar for each resource</strong> showing how much of the limit you&#39;ve used.</li><li>Any <strong>warnings</strong> and <strong>cleanup suggestions</strong>.</li><li>When the numbers were <strong>last calculated</strong>.</li></ul><p><img src="'+e+'" alt="Usage panel with warnings and exceeded limits"></p><p>Where you find it:</p><ul><li><strong>King</strong> — on the kingdom&#39;s detail page (via <strong>Kingdoms</strong>).</li><li><strong>Alliance Leader / Co-Leader</strong> — on the <strong><a href="./../how-to/my-alliance.html">My Alliance</a></strong> page.</li><li><strong>Supreme Admin</strong> — everywhere, plus a platform-wide manager (covered in the admin section).</li></ul><h2 id="two-ways-to-get-premium" tabindex="-1">Two ways to get premium <a class="header-anchor" href="#two-ways-to-get-premium" aria-label="Permalink to &quot;Two ways to get premium&quot;">​</a></h2><p>There are exactly two paths to unlocking premium, and both are covered step by step in this section:</p><ol><li><strong>Request it yourself</strong> — ask a Supreme Admin for a plan, arrange payment, and they activate it. Start at <a href="./request-subscription.html">Request a Subscription</a>.</li><li><strong>Receive a grant from your King</strong> — your King shares the kingdom&#39;s premium plan with your alliance, and you accept the offer. Start at <a href="./accept-grant.html">Accept a Premium Offer</a>.</li></ol><blockquote><p><strong>Important:</strong> an alliance does <strong>not</strong> automatically get premium just because its kingdom is premium. Premium reaches an alliance only through a <a href="./../getting-started/glossary.html#grant">grant</a> the King offers and the alliance accepts, or through the alliance&#39;s own direct plan. See <a href="./effective-plan.html">Which Plan Applies to You</a>.</p></blockquote><h2 id="who-can-do-what" tabindex="-1">Who can do what <a class="header-anchor" href="#who-can-do-what" aria-label="Permalink to &quot;Who can do what&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th style="text-align:center;">Supreme Admin</th><th style="text-align:center;">King</th><th style="text-align:center;">Alliance Leader</th><th style="text-align:center;">Co-Leader</th><th style="text-align:center;">Alliance Player</th></tr></thead><tbody><tr><td>See own usage panel</td><td style="text-align:center;">✅ (all)</td><td style="text-align:center;">✅ (kingdom)</td><td style="text-align:center;">✅ (alliance)</td><td style="text-align:center;">✅ (alliance)</td><td style="text-align:center;">✅ (own)</td></tr><tr><td>Request a subscription</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>Run cleanup</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>Offer a grant to an alliance</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (own kingdom)</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td>Accept / decline a grant offer</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">✅ (own alliance)</td><td style="text-align:center;">✅ (own alliance)</td><td style="text-align:center;">—</td></tr><tr><td>Approve requests / assign plans / suspend</td><td style="text-align:center;">✅ only</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li>New to the whole idea? Read <a href="./plans.html">Plans &amp; Tiers</a>, then <a href="./effective-plan.html">Which Plan Applies to You</a>.</li><li>Want premium now? <a href="./request-subscription.html">Request a Subscription</a> or <a href="./accept-grant.html">Accept a Premium Offer</a>.</li><li>Seeing warnings? <a href="./quota-warnings.html">Quota Warnings</a> and <a href="./cleanup.html">Run a Cleanup</a>.</li></ul>',20)])])}const y=a(s,[["render",l]]);export{m as __pageData,y as default};
